cat << 'EOF' > fix.pl
#!/usr/bin/perl
use strict;
use warnings;

my $original_input = `cat input.tex.bak`;

sub get_overfull_count {
    my ($text) = @_;
    open(my $fh, '>', 'input.tex') or die "Could not open input.tex: $!";
    print $fh $text;
    close $fh;

    my $output = `pdflatex -interaction=nonstopmode main.tex 2>&1`;
    my $count = 0;
    while ($output =~ /Overfull \\hbox/g) {
        $count++;
    }
    return $count;
}

open(my $syn_fh, '<', 'synonyms.txt') or die "Could not open synonyms.txt: $!";
my @synonyms;
while (my $line = <$syn_fh>) {
    chomp $line;
    my @words = split(/,\s*/, $line);
    push @synonyms, \@words;
}
close $syn_fh;

my $current_text = $original_input;
my $current_count = get_overfull_count($current_text);

print "Initial count: $current_count\n";

# Greedy search
for my $group (@synonyms) {
    # Find which word from this group is in the text
    my $found_word;
    for my $word (@$group) {
        # Check if word is in text (word boundaries)
        if ($current_text =~ /\b$word\b/) {
            $found_word = $word;
            last;
        }
    }

    if ($found_word) {
        my $best_word = $found_word;
        my $best_count = $current_count;

        for my $word (@$group) {
            next if $word eq $found_word;

            my $test_text = $current_text;
            $test_text =~ s/\b$found_word\b/$word/g;

            my $test_count = get_overfull_count($test_text);

            if ($test_count < $best_count) {
                $best_count = $test_count;
                $best_word = $word;
                print "Replacing '$found_word' with '$word' reduced count to $best_count\n";
            }
        }

        if ($best_word ne $found_word) {
            $current_text =~ s/\b$found_word\b/$best_word/g;
            $current_count = $best_count;
        }
    }
}

print "Final count: $current_count\n";
open(my $fh, '>', 'input.tex') or die "Could not open input.tex: $!";
print $fh $current_text;
close $fh;

EOF
./fix.pl

